using Ledgerly.Application.Abstractions; using Ledgerly.Application.Journals; using Ledgerly.Domain.Common; using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.Exceptions; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Application.Expenses; public sealed class ExpenseService { private readonly IExpenseRepository _expenseRepository; private readonly IContactRepository _contactRepository; private readonly ITaxCodeRepository _taxCodeRepository; private readonly JournalService _journalService; public ExpenseService(IExpenseRepository expenseRepository,IContactRepository contactRepository,ITaxCodeRepository taxCodeRepository,JournalService journalService){_expenseRepository=expenseRepository;_contactRepository=contactRepository;_taxCodeRepository=taxCodeRepository;_journalService=journalService;} public async Task<Result<ExpenseDto>> CreateAsync(CreateExpenseRequest request,CancellationToken cancellationToken=default){try{if(request.VendorId.HasValue){var contact=await _contactRepository.GetByIdAsync(request.OrganizationId,request.VendorId.Value,cancellationToken);if(contact is null||contact.ContactType!=ContactType.Vendor)return Result<ExpenseDto>.Failure("Vendor not found.");}var currency=new CurrencyCode(request.Currency);var expense=new Expense(request.OrganizationId,request.Description,request.ExpenseDate,currency,request.ExpenseAccountId,request.PaymentAccountId,new Money(request.Amount,currency),request.VendorId,request.TaxCodeId,request.ReceiptUrl);await _expenseRepository.AddAsync(expense,cancellationToken);return Result<ExpenseDto>.Success(Map(expense));}catch(DomainException e){return Result<ExpenseDto>.Failure(e.Message);}} public async Task<Result<ExpenseDto>> GetByIdAsync(Guid organizationId,Guid expenseId,CancellationToken cancellationToken=default){var expense=await _expenseRepository.GetByIdAsync(organizationId,expenseId,cancellationToken);return expense is null?Result<ExpenseDto>.Failure("Expense not found."):Result<ExpenseDto>.Success(Map(expense));} public async Task<Result<ExpenseDto>> SetReceiptAsync(Guid organizationId,Guid expenseId,SetExpenseReceiptRequest request,CancellationToken cancellationToken=default){try{var expense=await _expenseRepository.GetByIdAsync(organizationId,expenseId,cancellationToken);if(expense is null)return Result<ExpenseDto>.Failure("Expense not found.");expense.SetReceipt(request.ReceiptUrl);await _expenseRepository.UpdateAsync(expense,cancellationToken);return Result<ExpenseDto>.Success(Map(expense));}catch(DomainException e){return Result<ExpenseDto>.Failure(e.Message);}} public async Task<Result<ExpenseDto>> PostAsync(Guid organizationId,Guid expenseId,CancellationToken cancellationToken=default){try{var expense=await _expenseRepository.GetByIdAsync(organizationId,expenseId,cancellationToken);if(expense is null)return Result<ExpenseDto>.Failure("Expense not found.");var rate=await RateAsync(expense,cancellationToken);expense.Post(rate);var journal=await PostJournalAsync(expense,rate,cancellationToken);if(journal.IsFailure)return Result<ExpenseDto>.Failure(journal.Error!);expense.AttachJournalEntry(journal.Value!.Id);await _expenseRepository.UpdateAsync(expense,cancellationToken);return Result<ExpenseDto>.Success(Map(expense));}catch(DomainException e){return Result<ExpenseDto>.Failure(e.Message);}} public async Task<Result<ExpenseDto>> VoidAsync(Guid organizationId,Guid expenseId,CancellationToken cancellationToken=default){try{var expense=await _expenseRepository.GetByIdAsync(organizationId,expenseId,cancellationToken);if(expense is null)return Result<ExpenseDto>.Failure("Expense not found.");if(expense.JournalEntryId.HasValue){var rev=await _journalService.ReverseAsync(organizationId,expense.JournalEntryId.Value,cancellationToken);if(rev.IsFailure)return Result<ExpenseDto>.Failure(rev.Error!);}expense.Void();await _expenseRepository.UpdateAsync(expense,cancellationToken);return Result<ExpenseDto>.Success(Map(expense));}catch(DomainException e){return Result<ExpenseDto>.Failure(e.Message);}} private async Task<Result<JournalEntryDto>> PostJournalAsync(Expense expense,decimal rate,CancellationToken ct){var draft=await _journalService.CreateDraftAsync(new CreateJournalRequest(expense.OrganizationId,expense.ExpenseDate,null,$"Expense {expense.Description}",expense.Currency.Value),ct);if(draft.IsFailure)return Result<JournalEntryDto>.Failure(draft.Error!);var id=draft.Value!.Id;await _journalService.AddLineAsync(expense.OrganizationId,id,new AddJournalLineRequest(expense.ExpenseAccountId,expense.Amount.Amount,0m,null),ct);if(expense.TaxAmount.Amount>0m&&expense.TaxCodeId is Guid taxCodeId){var tc=await _taxCodeRepository.GetByIdAsync(expense.OrganizationId,taxCodeId,ct);if(tc is null)return Result<JournalEntryDto>.Failure("Tax code not found.");await _journalService.AddLineAsync(expense.OrganizationId,id,new AddJournalLineRequest(tc.LiabilityAccountId,expense.TaxAmount.Amount,0m,null),ct);}await _journalService.AddLineAsync(expense.OrganizationId,id,new AddJournalLineRequest(expense.PaymentAccountId,0m,expense.TotalAmount.Amount,null),ct);return await _journalService.PostAsync(expense.OrganizationId,id,ct);} private async Task<decimal> RateAsync(Expense expense,CancellationToken ct){if(!expense.TaxCodeId.HasValue)return 0m;var t=await _taxCodeRepository.GetByIdAsync(expense.OrganizationId,expense.TaxCodeId.Value,ct);return t?.Rate??0m;} private static ExpenseDto Map(Expense expense)=>new(expense.Id,expense.OrganizationId,expense.Description,expense.ExpenseDate,expense.Currency.Value,expense.Amount.Amount,expense.TaxAmount.Amount,expense.TotalAmount.Amount,expense.ExpenseAccountId,expense.PaymentAccountId,expense.VendorId,expense.TaxCodeId,expense.ReceiptUrl,expense.Status,expense.JournalEntryId,expense.CreatedAt,expense.UpdatedAt); }
